let client: Client
let server: Server

async function connectPair(deps: AnimaMcpServerDeps) {
  const s = createAnimaMcpServer(deps)
  const c = new Client({ name: 'test-client', version: '1.0.0' })
  const [ct, st] = InMemoryTransport.createLinkedPair()
  await Promise.all([c.connect(ct), s.connect(st)])
  client = c
  server = s
}

afterEach(async () => {
  await client?.close()
  await server?.close()
})

it('test', async () => {
  await connectPair(createStubDeps())
  // assertions directly, no try/finally
})

WHY: Eliminates 8 identical try/finally blocks (~40 lines of boilerplate). afterEach is the idiomatic Vitest pattern for resource cleanup.

